47	/**
48	 * Returns `{ state, stage, dispatch, restart }`. If the authed user already
49	 * completed the onboarding submission server-side (per `user.onboarding`)
50	 * but hasn't reached chat yet, this hook resumes them past the Q&A so a
51	 * post-clear reload doesn't drop them back on Q1. Pass `skipAutoRedirect`
52	 * to keep them on this page when chat is reached (used by the page itself
53	 * which renders the chat stage inline).
54	 *
55	 * `restart` clears persisted state, dispatches `restartStart`, drops the
56	 * old conversation from chat store + IndexedDB, then calls the server
57	 * `/reset` endpoint. The reducer is locked via `isRestarting` until done.
58	 */
59	export function useOnboarding({
60	  skipAutoRedirect = false,
61	}: UseOnboardingArgs = {}): UseOnboardingReturn {
62	  const router = useRouter();
63	  const user = useUser();
64	  const { setUser, updateUser } = useUserActions();
65	  const [state, dispatch] = useReducer(reducer, initialState);
66	  const stage = getStage(state);
