121	    if (redirectedRef.current) return;
122	    if (stage !== "chat") return;
123	    const conversationId = state.server?.first_message_conversation_id;
124	    if (!conversationId) return;
125	    redirectedRef.current = true;
126	    router.push(`/c/${conversationId}`);
127	  }, [
128	    stage,
129	    state.server?.first_message_conversation_id,
130	    skipAutoRedirect,
131	    router,
132	  ]);
